// JavaScript code for the MetaDataFinder (MDF) / MDM local-search module
//
// PURPOSE
// -------
// This module lets the user select a local folder, recursively scans it for
// JSON files, keeps only JSON objects generated by MetaDataMaker, builds a list
// of filterable metadata paths, and evaluates user-built boolean queries.
//
// BROWSER SECURITY NOTE
// ---------------------
// Browsers do not expose absolute filesystem paths. Therefore, this module
// displays paths relative to the user-selected folder. With showDirectoryPicker()
// the selected folder name is prepended. With the fallback file input, the
// browser-provided webkitRelativePath is used when available.

// -----------------------------------------------------------------------------
// IIFE: Immediately Invoked Function Expression
// -----------------------------------------------------------------------------
// Everything is wrapped in an anonymous function that is executed immediately.
// This creates a private scope for constants, state variables, and helper
// functions. Only the explicitly exported functions at the bottom become
// visible as window.MDMFinder.
// Without this wrapper, top-level variables/functions could become global and
// potentially collide with theme scripts or future MDM scripts loaded on the
// same page.
(function () {
    "use strict"; // to catch common mistakes early

    // The marker used to recognize JSON files produced by MetaDataMaker.
    // A JSON file is accepted only if metadata.generated_by === MDM_GENERATOR.
    const MDM_GENERATOR = "MetaDataMaker";

    // During a long scan, the UI status is updated every N filesystem entries.
    // This avoids refreshing the page text after every single file, which would
    // be unnecessarily expensive for large folders.
    const STATUS_UPDATE_INTERVAL = 50;

    // All mutable data used by the Finder is kept in this one object.
    const state = {
        selectedRootLabel: "",  // Label for the selected target folder.
        scannedEntries: 0,      // Number of entries (files or dirs) scanned.
        jsonFilesSeen: 0,       // Number of .json files actually inspected.
        mdmFiles: [],           // Accepted MDM JSON files (1).
        parseErrors: [],        // Collect errors and keep scanning.
        skippedEntries: [],     // Entries skipped because access not allowed.
        keySet: new Set(),      // All filterable metadata paths found (2).
        queryElements: [],      // User-built query as a list of row objects.
        nextQueryId: 1,         // Unique incremental identifier for query rows.
        searchCancelRequested: false,    // Flag checked during scanning.
        isSearching: false      // True while a folder scan is running.
    };

    // (1): Accepted MDM JSON files. Each item of the array is an objects with
    //      this shape:
    // {
    //   name: file name only,
    //   path: selected-folder-relative path,
    //   size: file size in bytes,
    //   lastModified: browser-provided timestamp,
    //   metadata: parsed JSON object
    // }
    //
    // (2): Set of all filterable metadata paths found in accepted MDM JSON
    //      files. A Set automatically avoids duplicates.

    // -------------------------------------------------------------------------
    // Small DOM and formatting helpers
    // -------------------------------------------------------------------------

    // Just a convenience wrapper around 'document.getElementById()'
    function byId(id) {
        return document.getElementById(id);
    }

    // Remove all children from an element.
    // Used before re-rendering result boxes or query rows.
    function clearElement(element) {
        if (!element) return;
        while (element.firstChild) {
            element.removeChild(element.firstChild);
        }
    }

    // Append a single text line to a parent element.
    // textContent is used instead of innerHTML to avoid injecting HTML from
    // file names or metadata values.
    function appendTextLine(parent, text, className) {
        const line = document.createElement("div");
        if (className) line.className = className;
        line.textContent = text;
        parent.appendChild(line);
        return line;
    }

    // Give the browser a chance to repaint and respond to clicks during long
    // asynchronous scans. Without this, very large scans may make the UI feel
    // frozen even though the code is running.
    function yieldToBrowser() {
        return new Promise(resolve => window.setTimeout(resolve, 0));
    }

    // Case-insensitive check for JSON filenames.
    function isJsonFileName(fileName) {
        return String(fileName || "").toLowerCase().endsWith(".json");
    }

    // Format numbers using the user's locale.
    // E.g.: 12000 -> 12,000 or 12.000 depending on locale.
    function formatInteger(value) {
        return Number(value || 0).toLocaleString();
    }

    // -------------------------------------------------------------------------
    // Search status and UI state
    // -------------------------------------------------------------------------
    
    // Enable/disable the main search button and show/hide the cancel button.
    // This prevents the user from launching two scans at the same time.
    function setSearchBusy(isBusy) {
        state.isSearching = isBusy;

        const searchButton = byId("mdmfSearchButton");
        const cancelButton = byId("mdmfCancelButton");

        if (searchButton) {
            searchButton.disabled = isBusy;
            searchButton.textContent = isBusy ? "Searching..." : "Search MDM Files";
        }

        if (cancelButton) {
            cancelButton.hidden = !isBusy;
        }
    }

    // Update the message near the folder-search controls.
    // isError toggles a CSS class so error messages can be styled differently.
    function setSearchStatus(text, isError = false) {
        const status = byId("mdmfSearchStatus");
        if (!status) return;

        status.textContent = text;
        status.classList.toggle("mdmfError", Boolean(isError));
    }

    // Update the message near the filter controls.
    function setFilterStatus(text, isError = false) {
        const status = byId("mdmfFilterStatus");
        if (!status) return;

        status.textContent = text;
        status.classList.toggle("mdmfError", Boolean(isError));
    }

    // Reset all scan results and query rows before starting a new search.
    function resetSearchState() {
        state.selectedRootLabel = "";
        state.scannedEntries = 0;
        state.jsonFilesSeen = 0;
        state.mdmFiles = [];
        state.parseErrors = [];
        state.skippedEntries = [];
        state.keySet = new Set();
        state.searchCancelRequested = false;
        state.queryElements = [];
        state.nextQueryId = 1;

        renderQueryRows();
        renderInitialResults();
        renderFilteredResults([], "No filter applied.");
    }

    // Show live progress while the scan is still running.
    function updateScanStatus() {
        setSearchStatus(
            "Scanning " +
            formatInteger(state.scannedEntries) +
            " filesystem entries; " +
            formatInteger(state.jsonFilesSeen) +
            " JSON files inspected; " +
            formatInteger(state.mdmFiles.length) +
            " MDM files found."
        );
    }

    // Show final scan summary when the scan finishes or is cancelled.
    function finishScanStatus() {
        const cancelled = state.searchCancelRequested ? " Search cancelled." : " Search complete.";
        const errorSummary = state.parseErrors.length > 0
            ? " " + formatInteger(state.parseErrors.length) + " JSON parse/read errors."
            : "";
        const skippedSummary = state.skippedEntries.length > 0
            ? " " + formatInteger(state.skippedEntries.length) + " entries skipped."
            : "";

        setSearchStatus(
            formatInteger(state.mdmFiles.length) +
            " MDM files found in " +
            formatInteger(state.jsonFilesSeen) +
            " JSON files inspected." +
            cancelled +
            errorSummary +
            skippedSummary
        );
    }

    // -------------------------------------------------------------------------
    // Search entry point
    // -------------------------------------------------------------------------

    // Called when the user clicks "Search MDM Files".
    // It first tries the modern File System Access API. If that is unavailable
    // or fails for compatibility reasons, it falls back to the hidden
    // <input type="file" webkitdirectory> element.
    async function searchMdmFiles() {
        resetSearchState();
        setSearchBusy(true);
        setSearchStatus("Choose a folder to scan...");

        try {
            let usedModernPicker = false;

            // Modern Chromium-like browsers may provide showDirectoryPicker().
            // This provides a directory handle that can be recursively iterated.
            if ("showDirectoryPicker" in window) {
                usedModernPicker = await scanWithDirectoryPicker();
            }

            // Fallback path for browsers where showDirectoryPicker() is not
            // available or not usable. The hidden input is expected to exist in
            // MDM_MetaDataFinder.html.
            if (!usedModernPicker) {
                const fallbackInput = byId("mdmfFolderInput");
                if (fallbackInput) {
                    setSearchBusy(false);
                    setSearchStatus("Choose a folder using the fallback file picker...");
                    fallbackInput.click();
                    return;
                }

                setSearchStatus("No supported folder picker is available in this browser.", true);
            }
        } catch (err) {
            console.error("MetaDataFinder search failed:", err);
            setSearchStatus("Search failed: " + readableError(err), true);
        } finally {
            // If a modern-picker scan completed normally, the busy state is
            // still true here and must be cleared. In the fallback path, busy
            // was already cleared before opening the file picker.
            if (state.isSearching) {
                setSearchBusy(false);
            }
        }
    }

    // Modern folder picker scan.
    // Ask the user to choose a folder with showDirectoryPicker(), then scan it
    // recursively through FileSystemDirectoryHandle entries.
    async function scanWithDirectoryPicker() {
        let rootHandle;

        try {
            rootHandle = await window.showDirectoryPicker({ mode: "read" });
        } catch (err) {
            // User clicked Cancel. This is not an error and should not trigger
            // the fallback input immediately.
            if (err && err.name === "AbortError") {
                setSearchStatus("Folder selection cancelled.");
                return true;
            }

            // Some browsers may expose the method but fail due to context,
            // permissions, or implementation details. In that case, fallback.
            console.warn("showDirectoryPicker() failed; falling back to file input.", err);
            return false;
        }

        // Selected folder name, not an absolute filesystem path.
        state.selectedRootLabel = rootHandle.name || "selected-folder";

        // Recursive scan starts here.
        await walkDirectoryHandle(rootHandle, state.selectedRootLabel);

        // Sort results alphabetically by displayed path for stable UI output.
        state.mdmFiles.sort((a, b) => a.path.localeCompare(b.path));
        
        renderInitialResults();
        renderQueryRows();
        finishScanStatus();
        return true;
    }

    // Recursively walk a FileSystemDirectoryHandle.
    // directoryHandle: browser handle for the current folder.
    // displayPrefix: selected-folder-relative path shown in the UI.
    async function walkDirectoryHandle(directoryHandle, displayPrefix) {
        try {
            for await (const [name, handle] of directoryHandle.entries()) {
                if (state.searchCancelRequested) return;

                const displayPath = displayPrefix ? displayPrefix + "/" + name : name;
                state.scannedEntries++;

                if (handle.kind === "directory") {
                    // Recurse into subfolder.
                    await walkDirectoryHandle(handle, displayPath);
                } else if (handle.kind === "file" && isJsonFileName(name)) {
                    // Read and inspect JSON files only.
                    try {
                        const file = await handle.getFile();
                        await inspectJsonFile(file, displayPath);
                    } catch (err) {
                        state.parseErrors.push({ path: displayPath, error: readableError(err) });
                    }
                }

                // Periodically update status and yield to the UI.
                if (state.scannedEntries % STATUS_UPDATE_INTERVAL === 0) {
                    updateScanStatus();
                    await yieldToBrowser();
                }
            }
        } catch (err) {
            // Directory iteration can fail for permission or OS-level reasons.
            // The scan records the skipped folder and continues elsewhere.
            state.skippedEntries.push({ path: displayPrefix, error: readableError(err) });
        }
    }

    // Fallback folder-input scan.
    // Called by the hidden folder input when the user selects a directory.
    // The file input provides a flat FileList, usually with each file carrying
    // a webkitRelativePath that preserves the selected directory hierarchy.
    async function handleFolderInput(fileList) {
        resetSearchState();
        setSearchBusy(true);

        try {
            const files = Array.from(fileList || []);
            if (files.length === 0) {
                setSearchStatus("Folder selection cancelled.");
                return;
            }

            state.selectedRootLabel = inferRootLabelFromFiles(files);

            for (let i = 0; i < files.length; i++) {
                if (state.searchCancelRequested) break;

                const file = files[i];
                const displayPath = file.webkitRelativePath || file.name;
                state.scannedEntries++;

                if (isJsonFileName(file.name)) {
                    await inspectJsonFile(file, displayPath);
                }

                if (state.scannedEntries % STATUS_UPDATE_INTERVAL === 0) {
                    updateScanStatus();
                    await yieldToBrowser();
                }
            }

            state.mdmFiles.sort((a, b) => a.path.localeCompare(b.path));
            renderInitialResults();
            renderQueryRows();
            finishScanStatus();
        } catch (err) {
            console.error("MetaDataFinder fallback scan failed:", err);
            setSearchStatus("Search failed: " + readableError(err), true);
        } finally {
            setSearchBusy(false);

            // Resetting the input value allows the user to select the same
            // folder again and still trigger a change event.
            const fallbackInput = byId("mdmfFolderInput");
            if (fallbackInput) {
                fallbackInput.value = "";
            }
        }
    }

    // Infer a readable root label from the first file path returned by the
    // fallback picker. Example:
    //
    //   ExperimentFolder/subfolder/file.json -> ExperimentFolder
    function inferRootLabelFromFiles(files) {
        const firstPath = files[0]?.webkitRelativePath || "";
        if (!firstPath) return "selected-files";
        return firstPath.split("/")[0] || "selected-folder";
    }

    // -------------------------------------------------------------------------
    // JSON inspection
    // -------------------------------------------------------------------------

    // Read one File object, parse it as JSON, and keep it only if it is an MDM
    // metadata file.
    async function inspectJsonFile(file, displayPath) {
        state.jsonFilesSeen++;

        try {
            const text = await file.text();
            const metadata = JSON.parse(text);

            if (isMdmMetadata(metadata)) {
                const entry = {
                    name: file.name,
                    path: displayPath,
                    size: file.size,
                    lastModified: file.lastModified || null,
                    metadata
                };

                state.mdmFiles.push(entry);

                // Add all metadata paths found in this file to the global key
                // set used by the Key dropdown menu.
                collectFilterablePaths(metadata, "", state.keySet);
            }
        } catch (err) {
            // Malformed JSON or read errors are recorded but do not stop the
            // whole folder scan.
            state.parseErrors.push({ path: displayPath, error: readableError(err) });
        }
    }

    // Test whether a parsed JSON value is an MDM metadata object.
    // Only plain objects are accepted; arrays/null/primitives are rejected.
    function isMdmMetadata(value) {
        return value !== null &&
            typeof value === "object" &&
            !Array.isArray(value) &&
            value.generated_by === MDM_GENERATOR;
    }

    // Convert different error-like values into a readable string.
    function readableError(err) {
        if (!err) return "unknown error";
        return err.message || err.name || String(err);
    }

    // -------------------------------------------------------------------------
    // Metadata path collection and lookup
    // -------------------------------------------------------------------------

    // Recursively inspect a value and add every useful metadata path to keySet.
    // path is the dot-separated path accumulated so far.
    //
    // Array convention:
    // If an array is found at, e.g., "events", the array itself is added as
    // "events" and child object paths use "events[]", for example:
    //
    //   events[].time
    //   events[].stimulus
    function collectFilterablePaths(value, path, keySet) {
        if (value === undefined) return;

        // Primitive or null: the current path is directly filterable.
        if (value === null || typeof value !== "object") {
            if (path) keySet.add(path);
            return;
        }

        // Array: add the array path itself, then inspect each item using [] to
        // mark that the path traverses array elements.
        if (Array.isArray(value)) {
            if (path) keySet.add(path);
            const arrayPath = path ? path + "[]" : "[]";

            value.forEach(item => {
                collectFilterablePaths(item, arrayPath, keySet);
            });
            return;
        }

        // Some MDM fields are objects like:
        //
        //   { "value": 3.2, "unit": "MΩ" }
        //
        // For these, the parent path is also useful because a user may want to
        // filter by "patch_clamp.seal_resistance" rather than specifically by
        // "patch_clamp.seal_resistance.value".
        if (path && Object.prototype.hasOwnProperty.call(value, "value")) {
            keySet.add(path);
        }

        // Recurse into object properties.
        Object.keys(value).forEach(key => {
            const childPath = path ? path + "." + key : key;
            collectFilterablePaths(value[key], childPath, keySet);
        });
    }

    // Retrieve all values matching a dot-separated metadata path. Example:
    //
    //   getValuesAtPath(metadata, "cell_cultures.cell_type")
    //
    // returns an array, not a single value, because paths can pass through arrays.
    function getValuesAtPath(root, path) {
        if (!path) return [root];

        const segments = path.split(".");
        let contexts = [root];

        segments.forEach(segment => {
            const expandArray = segment.endsWith("[]");
            const key = expandArray ? segment.slice(0, -2) : segment;
            const nextContexts = [];

            contexts.forEach(context => {
                if (context === null || context === undefined) return;

                if (Array.isArray(context)) {
                    context.forEach(item => {
                        addSegmentValue(item, key, expandArray, nextContexts);
                    });
                } else {
                    addSegmentValue(context, key, expandArray, nextContexts);
                }
            });

            contexts = nextContexts;
        });

        return contexts.filter(value => value !== undefined);
    }

    // Helper used by getValuesAtPath() for one path segment.
    // If expandArray is true and the extracted value is an array, each array
    // item is pushed separately to output.
    function addSegmentValue(context, key, expandArray, output) {
        if (context === null || context === undefined) return;

        let value;

        if (key === "") {
            value = context;
        } else if (typeof context === "object" && key in context) {
            value = context[key];
        } else {
            return;
        }

        if (expandArray && Array.isArray(value)) {
            value.forEach(item => output.push(item));
        } else {
            output.push(value);
        }
    }

    function extractComparableValues(value, output = []) {
        if (value === undefined) return output;

        if (value === null) {
            output.push(null);
            return output;
        }

        if (Array.isArray(value)) {
            value.forEach(item => extractComparableValues(item, output));
            return output;
        }

        if (typeof value === "object") {
            const hasValue = Object.prototype.hasOwnProperty.call(value, "value");
            const hasUnit = Object.prototype.hasOwnProperty.call(value, "unit");

            if (hasValue) output.push(value.value);
            if (hasUnit) output.push(value.unit);
            if (hasValue && hasUnit) output.push(String(value.value) + " " + String(value.unit));

            try {
                output.push(JSON.stringify(value));
            } catch (err) {
                output.push(String(value));
            }
            return output;
        }

        output.push(value);
        return output;
    }

    









    // ------------------------------------------------------------------
    // Query UI model and rendering
    // ------------------------------------------------------------------

    function addQueryElement(kind) {
        const normalizedKind = String(kind || "").toLowerCase();
        const allowedKinds = ["kv", "and", "or", "open", "close"];
        if (!allowedKinds.includes(normalizedKind)) return;

        state.queryElements.push({
            id: state.nextQueryId++,
            kind: normalizedKind,
            key: "",
            value: ""
        });

        renderQueryRows();
    }

    function removeQueryElement(id) {
        state.queryElements = state.queryElements.filter(element => element.id !== Number(id));
        renderQueryRows();
    }

    function clearQuery() {
        state.queryElements = [];
        renderQueryRows();
        renderFilteredResults([], "No filter applied.");
        setFilterStatus("No filter applied.");
    }

    function updateQueryElement(id, patch) {
        const element = state.queryElements.find(item => item.id === Number(id));
        if (!element) return;
        Object.assign(element, patch);
    }

    function renderQueryRows() {
        const container = byId("mdmfQueryRows");
        if (!container) return;

        clearElement(container);

        if (state.queryElements.length === 0) {
            appendTextLine(container, "Add query elements with the buttons above.", "mdmfEmptyQuery stdMetaField");
            return;
        }

        state.queryElements.forEach(element => {
            const row = document.createElement("div");
            row.className = "mdmfQueryRow stdMetaField";

            const deleteButton = document.createElement("button");
            deleteButton.className = "smallButton mdmfBinButton";
            deleteButton.type = "button";
            deleteButton.textContent = "[ x ]";
            deleteButton.title = "Delete this query element";
            deleteButton.addEventListener("click", () => removeQueryElement(element.id));
            row.appendChild(deleteButton);

            if (element.kind === "kv") {
                renderKeyValueQueryElement(row, element);
            } else {
                const token = document.createElement("div");
                token.className = "mdmfLogicalToken";
                token.textContent = queryKindLabel(element.kind);
                row.appendChild(token);
            }

            container.appendChild(row);
        });
    }

    function renderKeyValueQueryElement(row, element) {
        const label = document.createElement("label");
        label.className = "metaLabel";
        label.textContent = "Key-Value:";
        row.appendChild(label);

        const keySelect = document.createElement("select");
        keySelect.className = "mdmfInput mdmfKeySelect";
        keySelect.value = element.key || "";
        keySelect.addEventListener("change", () => {
            updateQueryElement(element.id, { key: keySelect.value });
        });
        populateKeySelect(keySelect, element.key);
        row.appendChild(keySelect);

        const valueInput = document.createElement("input");
        valueInput.className = "mdmfInput mdmfValueInput";
        valueInput.type = "text";
        valueInput.placeholder = "Value; empty = key exists";
        valueInput.value = element.value || "";
        valueInput.addEventListener("input", () => {
            updateQueryElement(element.id, { value: valueInput.value });
        });
        row.appendChild(valueInput);
    }

    function queryKindLabel(kind) {
        switch (kind) {
            case "and":
                return "AND";
            case "or":
                return "OR";
            case "open":
                return "(";
            case "close":
                return ")";
            default:
                return kind;
        }
    }

    function populateKeySelect(select, selectedValue) {
        if (!select) return;

        clearElement(select);

        const placeholder = document.createElement("option");
        placeholder.value = "";
        placeholder.textContent = state.keySet.size > 0 ? "-- choose metadata key --" : "-- no keys available --";
        placeholder.disabled = true;
        placeholder.selected = !selectedValue;
        select.appendChild(placeholder);

        const keys = Array.from(state.keySet).sort((a, b) => a.localeCompare(b));
        keys.forEach(key => {
            const option = document.createElement("option");
            option.value = key;
            option.textContent = key;
            if (key === selectedValue) {
                option.selected = true;
            }
            select.appendChild(option);
        });

        select.disabled = keys.length === 0;
    }

    // ---------------------------------------------------------------------
    // Query compilation and filtering

    function applyFilter() {
        if (state.mdmFiles.length === 0) {
            setFilterStatus("No MDM files are available. Search a folder first.", true);
            renderFilteredResults([], "No filtered results.");
            return;
        }

        let compiled;
        try {
            compiled = compileQuery(state.queryElements);
        } catch (err) {
            setFilterStatus("Invalid query: " + readableError(err), true);
            renderFilteredResults([], "Invalid query. Fix the query rows and apply again.");
            return;
        }

        let matches;
        if (compiled.length === 0) {
            matches = state.mdmFiles.slice();
            setFilterStatus("No query elements: showing all " + formatInteger(matches.length) + " MDM files.");
        } else {
            matches = state.mdmFiles.filter(entry => evaluateCompiledQuery(compiled, entry.metadata));
            setFilterStatus(
                formatInteger(matches.length) +
                " of " +
                formatInteger(state.mdmFiles.length) +
                " MDM files match the query."
            );
        }

        renderFilteredResults(matches);
    }

    function compileQuery(elements) {
        if (!elements || elements.length === 0) return [];

        const output = [];
        const operators = [];
        let expectOperand = true;

        elements.forEach((element, index) => {
            const position = index + 1;

            if (element.kind === "kv") {
                if (!expectOperand) {
                    throw new Error("missing AND/OR before Key-Value at row " + position);
                }
                if (!element.key) {
                    throw new Error("missing key in Key-Value row " + position);
                }

                output.push(element);
                expectOperand = false;
                return;
            }

            if (element.kind === "open") {
                if (!expectOperand) {
                    throw new Error("missing AND/OR before '(' at row " + position);
                }

                operators.push(element);
                expectOperand = true;
                return;
            }

            if (element.kind === "close") {
                if (expectOperand) {
                    throw new Error("empty parentheses or missing Key-Value before ')' at row " + position);
                }

                let foundOpen = false;
                while (operators.length > 0) {
                    const top = operators.pop();
                    if (top.kind === "open") {
                        foundOpen = true;
                        break;
                    }
                    output.push(top);
                }

                if (!foundOpen) {
                    throw new Error("unmatched ')' at row " + position);
                }

                expectOperand = false;
                return;
            }

            if (element.kind === "and" || element.kind === "or") {
                if (expectOperand) {
                    throw new Error("missing Key-Value before " + queryKindLabel(element.kind) + " at row " + position);
                }

                while (operators.length > 0) {
                    const top = operators[operators.length - 1];
                    if (top.kind === "open") break;
                    if (operatorPrecedence(top.kind) >= operatorPrecedence(element.kind)) {
                        output.push(operators.pop());
                    } else {
                        break;
                    }
                }

                operators.push(element);
                expectOperand = true;
                return;
            }

            throw new Error("unknown query element at row " + position);
        });

        if (expectOperand) {
            throw new Error("query cannot end with AND, OR, or '('");
        }

        while (operators.length > 0) {
            const top = operators.pop();
            if (top.kind === "open") {
                throw new Error("unmatched '('");
            }
            output.push(top);
        }

        return output;
    }

    function operatorPrecedence(kind) {
        if (kind === "and") return 2;
        if (kind === "or") return 1;
        return 0;
    }

    function evaluateCompiledQuery(compiled, metadata) {
        if (!compiled || compiled.length === 0) return true;

        const stack = [];

        compiled.forEach(token => {
            if (token.kind === "kv") {
                stack.push(evaluateKeyValue(metadata, token.key, token.value));
                return;
            }

            if (token.kind === "and" || token.kind === "or") {
                const right = stack.pop();
                const left = stack.pop();
                stack.push(token.kind === "and" ? Boolean(left && right) : Boolean(left || right));
            }
        });

        return stack.length === 1 ? Boolean(stack[0]) : false;
    }

    function evaluateKeyValue(metadata, keyPath, queryValue) {
        const rawValues = getValuesAtPath(metadata, keyPath);
        if (rawValues.length === 0) return false;

        const query = String(queryValue || "").trim();
        if (query === "") {
            return rawValues.some(value => value !== undefined);
        }

        return rawValues.some(value => valueMatchesQuery(value, query));
    }

    function valueMatchesQuery(rawValue, query) {
        const queryLower = query.toLowerCase();
        const queryBoolean = parseBoolean(query);
        const queryNumber = parseNumberStrict(query);
        const values = extractComparableValues(rawValue);

        return values.some(value => {
            if (value === null) {
                return queryLower === "null";
            }

            if (typeof value === "boolean") {
                return queryBoolean === null
                    ? String(value).toLowerCase().includes(queryLower)
                    : value === queryBoolean;
            }

            if (typeof value === "number") {
                return queryNumber === null
                    ? String(value).toLowerCase().includes(queryLower)
                    : value === queryNumber;
            }

            return String(value).toLowerCase().includes(queryLower);
        });
    }

    function parseBoolean(text) {
        const value = String(text || "").trim().toLowerCase();
        if (value === "true") return true;
        if (value === "false") return false;
        return null;
    }

    function parseNumberStrict(text) {
        const trimmed = String(text || "").trim();
        if (trimmed === "") return null;
        if (!/^[-+]?\d+(\.\d+)?([eE][-+]?\d+)?$/.test(trimmed)) return null;

        const number = Number(trimmed);
        return Number.isFinite(number) ? number : null;
    }





    // ---------------------------------------------------------------------
    // Results rendering

    function renderInitialResults() {
        const container = byId("mdmfInitialResults");
        if (!container) return;

        clearElement(container);

        if (state.mdmFiles.length === 0) {
            appendTextLine(container, "No MDM JSON files found yet.", "mdmfMutedLine");
            return;
        }

        appendTextLine(
            container,
            formatInteger(state.mdmFiles.length) +
            " MDM JSON files found; " +
            formatInteger(state.keySet.size) +
            " filterable metadata keys collected.",
            "mdmfSummaryLine"
        );
        appendTextLine(container, "Paths are shown relative to the selected folder.", "mdmfMutedLine");

        const list = document.createElement("div");
        list.className = "mdmfFileList";

        state.mdmFiles.forEach(entry => {
            appendFileLine(list, entry);
        });

        container.appendChild(list);
    }

    function renderFilteredResults(matches, message) {
        const container = byId("mdmfFilteredResults");
        if (!container) return;

        clearElement(container);

        if (message) {
            appendTextLine(container, message, "mdmfMutedLine");
            return;
        }

        if (!matches || matches.length === 0) {
            appendTextLine(container, "No files match the current filter.", "mdmfMutedLine");
            return;
        }

        appendTextLine(container, formatInteger(matches.length) + " filtered files:", "mdmfSummaryLine");

        const list = document.createElement("div");
        list.className = "mdmfFileList";

        matches.forEach(entry => {
            appendFileLine(list, entry);
        });

        container.appendChild(list);
    }

    function appendFileLine(parent, entry) {
        const line = document.createElement("div");
        line.className = "mdmfFileLine";

        const path = document.createElement("code");
        path.className = "mdmfFilePath";
        path.textContent = entry.path;
        line.appendChild(path);

        const meta = document.createElement("div");
        meta.className = "mdmfFileMeta";
        meta.textContent = makeEntrySummary(entry);
        line.appendChild(meta);

        parent.appendChild(line);
    }

    function makeEntrySummary(entry) {
        const metadata = entry.metadata || {};
        const parts = [];

        const date = getFirstComparable(metadata, "general.date");
        const cellType = getFirstComparable(metadata, "cell_cultures.cell_type");
        const condition = getFirstComparable(metadata, "cell_cultures.experimental_condition");
        const configuration = getFirstComparable(metadata, "patch_clamp.configuration");

        if (date) parts.push("date: " + date);
        if (cellType) parts.push("cell: " + cellType);
        if (condition) parts.push("condition: " + condition);
        if (configuration) parts.push("configuration: " + configuration);

        return parts.length > 0 ? "[" + parts.join("; ") + "]" : "";
    }

    function getFirstComparable(metadata, keyPath) {
        const raw = getValuesAtPath(metadata, keyPath);
        if (raw.length === 0) return "";

        const values = extractComparableValues(raw[0]).filter(value => {
            return value !== null && value !== undefined && String(value).trim() !== "";
        });

        return values.length > 0 ? String(values[0]) : "";
    }









    // ---------------------------------------------------------------------

    function cancelSearch() {
        state.searchCancelRequested = true;
        setSearchStatus("Cancelling search after the current file/folder finishes...");
    }

    document.addEventListener("DOMContentLoaded", function () {
        renderInitialResults();
        renderQueryRows();
        renderFilteredResults([], "Filtered MDM JSON files will be listed here.");
    });

    window.MDMFinder = {
        searchMdmFiles,
        cancelSearch,
        handleFolderInput,
        addQueryElement,
        removeQueryElement,
        clearQuery,
        applyFilter
    };
})();
